		// - EntityRestClient.loadMultiple would need a Map<elementId, ownerKey> or similar
		// - OR: Load entities one by one when they have different owner keys
		// - OR: Change the API to support per-entity callbacks for key resolution

		// The exact fix depends on the architecture and performance requirements.

		expect(true).toBe(true)
	})
})

